from semantic_kernel import Kernel
from semantic_kernel.functions import kernel_function

class WeatherPlugin:
    @kernel_function(
        name="get_current_weather",
        description="Get the current weather for a city.",
    )
    def get_current_weather(self, city: str) -> str:
        # In production: call a real weather API
        return f"It is sunny and 22 degrees in {city}."

    @kernel_function(
        name="get_forecast",
        description="Get a 3-day weather forecast for a city.",
    )
    def get_forecast(self, city: str, days: int = 3) -> str:
        return f"{days}-day forecast for {city}: partly cloudy."

kernel = Kernel()
kernel.add_plugin(WeatherPlugin(), plugin_name="weather")

# Programmatic invocation
result = await kernel.invoke("weather", "get_current_weather", city="London")
print(str(result))   # "It is sunny and 22 degrees in London."

from pydantic import BaseModel, Field
from semantic_kernel.functions import kernel_function

class FlightQuery(BaseModel):
    origin: str = Field(description="IATA departure airport code")
    destination: str = Field(description="IATA arrival airport code")
    date: str = Field(description="Travel date in YYYY-MM-DD format")

class FlightPlugin:
    @kernel_function(
        name="search_flights",
        description="Search for available flights between two airports.",
    )
    def search_flights(self, query: FlightQuery) -> str:
        return f"Found 3 flights from {query.origin} to {query.destination} on {query.date}."

from semantic_kernel.connectors.ai.open_ai import OpenAIChatPromptExecutionSettings
from semantic_kernel.connectors.ai.function_choice_behavior import FunctionChoiceBehavior

# Allow only specific functions (safest option)
settings = OpenAIChatPromptExecutionSettings(
    service_id="chat",
    function_choice_behavior=FunctionChoiceBehavior.Auto(
        filters={"included_functions": ["weather-get_current_weather", "weather-get_forecast"]}
    ),
)

# Or exclude specific functions
settings_exclude = OpenAIChatPromptExecutionSettings(
    service_id="chat",
    function_choice_behavior=FunctionChoiceBehavior.Auto(
        filters={"excluded_functions": ["petstore-deletePet"]}
    ),
)

import httpx

class NewsPlugin:
    def __init__(self, api_key: str):
        self._client = httpx.AsyncClient(headers={"Authorization": f"Bearer {api_key}"})

    @kernel_function(name="get_headlines", description="Fetch the latest news headlines.")
    async def get_headlines(self, topic: str) -> str:
        response = await self._client.get(
            "https://newsapi.org/v2/top-headlines",
            params={"q": topic, "pageSize": 5},
        )
        articles = response.json().get("articles", [])
        return "\n".join(a["title"] for a in articles)

kernel.add_plugin(NewsPlugin(api_key="sk-..."), plugin_name="news")
